Since we found this 0.5 CPU resource request to be much more ideal for these IO-bound read tasks, it would be nice if we could preserve this resource request when no stage fusion is taking place.

What if we merged resource requests when fusing stages, taking the maximum when encountering conflicts?
```python
def fuse(self, prev: Stage):
    # ...
    ray_remote_args = self._merge_ray_remote_args(prev.ray_remote_args)
    return OneToOneStage(name, block_fn, prev.compute, ray_remote_args)

def _merge_ray_remote_args(ray_remote_args: Dict[str, Any]) -> Dict[str, Any]:
    if "num_cpus" in ray_remote_args or "num_cpus" in self.ray_remote_args:
        ray_remote_args["num_cpus"] = max(
            ray_remote_args.get("num_cpus", default_num_cpus),
            self.ray_remote_args.get("num_cpus", default_num_cpus))
    # Same for num_gpus, memory, etc.
    self_resources = self.ray_remote_args.get("resources")
    if self_resources is not None:
        if "resources" not in ray_remote_args:
            ray_remote_args["resources"] = {}
        resources = ray_remote_args["resources"]
        for key, resource in self_resources:
            resources][key] = max(resource, resources[key]) if key in resources else resource
    return ray_remote_args
```

